contracts/core/PointEconomyContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./StudentRegistryContract.sol";

/**
 * @title PointEconomyContract
 * @notice Manages dynamic point-based reward system with AI quality bonuses
 * @dev 1000 points = 1 INR = ~1 SHM
 */
contract PointEconomyContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REWARD_MANAGER_ROLE = keccak256("REWARD_MANAGER_ROLE");

    StudentRegistryContract public studentRegistry;

    uint256 public constant POINTS_TO_INR_RATIO = 1000; // 1000 points = 1 INR
    uint256 public constant POINTS_TO_SHM_RATIO = 1000; // 1000 points = 1 SHM

    enum ActivityType {
        BasicFeedback,
        FacultyRating,
        InfrastructureReport,
        InfrastructureWithImage,
        AIEnhancementAccepted,
        PeerVerification,
        WeeklyConsistency,
        AITrainingContribution
    }

    struct PointTransaction {
        address user;
        ActivityType activity;
        uint256 basePoints;
        uint256 qualityBonus;
        uint256 totalPoints;
        uint256 timestamp;
        string description;
    }

    struct UserPointsData {
        uint256 totalPoints;
        uint256 lifetimePoints;
        uint256 redeemedPoints;
        uint256 lastActivityTime;
        uint256 consecutiveDays;
        uint256 transactionCount;
    }

    // Base points for each activity
    mapping(ActivityType => uint256) public basePoints;
    mapping(ActivityType => uint256) public maxQualityBonus;

    // User data
    mapping(address => UserPointsData) public userPoints;
    mapping(address => PointTransaction[]) public userTransactions;
    mapping(address => mapping(uint256 => bool)) public dailyActivity; // user => day => hasActivity

    uint256 public totalPointsIssued;
    uint256 public totalPointsRedeemed;
    uint256 public totalTransactions;

    // Events
    event PointsAwarded(
        address indexed user,
        ActivityType activity,
        uint256 basePoints,
        uint256 qualityBonus,
        uint256 totalPoints,
        uint256 timestamp
    );
    event PointsRedeemed(address indexed user, uint256 points, uint256 shmAmount);
    event PointsTransferred(address indexed from, address indexed to, uint256 points);
    event StreakBonusAwarded(address indexed user, uint256 consecutiveDays, uint256 bonusPoints);
    event BasePointsUpdated(ActivityType activity, uint256 newBasePoints);

    constructor(address _studentRegistry) {
        require(_studentRegistry != address(0), "Invalid student registry");
        
        studentRegistry = StudentRegistryContract(_studentRegistry);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(REWARD_MANAGER_ROLE, msg.sender);

        // Initialize base points
        basePoints[ActivityType.BasicFeedback] = 10;
        basePoints[ActivityType.FacultyRating] = 25;
        basePoints[ActivityType.InfrastructureReport] = 30;
        basePoints[ActivityType.InfrastructureWithImage] = 50;
        basePoints[ActivityType.AIEnhancementAccepted] = 20;
        basePoints[ActivityType.PeerVerification] = 15;
        basePoints[ActivityType.WeeklyConsistency] = 100;
        basePoints[ActivityType.AITrainingContribution] = 50;

        // Initialize max quality bonuses
        maxQualityBonus[ActivityType.BasicFeedback] = 15;
        maxQualityBonus[ActivityType.FacultyRating] = 25;
        maxQualityBonus[ActivityType.InfrastructureReport] = 20;
        maxQualityBonus[ActivityType.InfrastructureWithImage] = 30;
        maxQualityBonus[ActivityType.AIEnhancementAccepted] = 0;
        maxQualityBonus[ActivityType.PeerVerification] = 10;
        maxQualityBonus[ActivityType.WeeklyConsistency] = 50;
        maxQualityBonus[ActivityType.AITrainingContribution] = 0;
    }

    /**
     * @notice Award points to user
     * @param user Address of the user
     * @param activity Type of activity
     * @param aiQualityScore AI quality score (0-100)
     * @param description Description of the activity
     */
    function awardPoints(
        address user,
        ActivityType activity,
        uint8 aiQualityScore,
        string memory description
    ) external onlyRole(REWARD_MANAGER_ROLE) {
        require(studentRegistry.isVerifiedStudent(user), "Not verified student");
        require(aiQualityScore <= 100, "Invalid quality score");

        uint256 base = basePoints[activity];
        uint256 bonus = calculateQualityBonus(activity, aiQualityScore);
        uint256 total = base + bonus;

        // Update user points
        userPoints[user].totalPoints += total;
        userPoints[user].lifetimePoints += total;
        userPoints[user].lastActivityTime = block.timestamp;
        userPoints[user].transactionCount++;

        // Record transaction
        userTransactions[user].push(PointTransaction({
            user: user,
            activity: activity,
            basePoints: base,
            qualityBonus: bonus,
            totalPoints: total,
            timestamp: block.timestamp,
            description: description
        }));

        // Update daily activity
        uint256 today = block.timestamp / 1 days;
        if (!dailyActivity[user][today]) {
            dailyActivity[user][today] = true;
            _updateStreak(user, today);
        }

        totalPointsIssued += total;
        totalTransactions++;

        emit PointsAwarded(user, activity, base, bonus, total, block.timestamp);
    }

    /**
     * @notice Calculate quality bonus based on AI score
     * @param activity Type of activity
     * @param aiQualityScore AI quality score (0-100)
     * @return Bonus points
     */
    function calculateQualityBonus(ActivityType activity, uint8 aiQualityScore) 
        public 
        view 
        returns (uint256) 
    {
        uint256 maxBonus = maxQualityBonus[activity];
        if (maxBonus == 0) return 0;

        // Linear scaling: higher quality = more bonus
        return (maxBonus * aiQualityScore) / 100;
    }

    /**
     * @notice Update user's consecutive days streak
     * @param user Address of the user
     * @param today Current day number
     */
    function _updateStreak(address user, uint256 today) internal {
        uint256 yesterday = today - 1;
        
        if (dailyActivity[user][yesterday]) {
            // Streak continues
            userPoints[user].consecutiveDays++;
            
            // Award streak bonus every 7 days
            if (userPoints[user].consecutiveDays % 7 == 0) {
                uint256 streakBonus = 50 * (userPoints[user].consecutiveDays / 7);
                userPoints[user].totalPoints += streakBonus;
                userPoints[user].lifetimePoints += streakBonus;
                
                emit StreakBonusAwarded(user, userPoints[user].consecutiveDays, streakBonus);
            }
        } else {
            // Streak broken, reset
            userPoints[user].consecutiveDays = 1;
        }
    }

    /**
     * @notice Redeem points for SHM
     * @param points Amount of points to redeem
     */
    function redeemPoints(uint256 points) external nonReentrant {
        require(userPoints[msg.sender].totalPoints >= points, "Insufficient points");
        require(points >= POINTS_TO_SHM_RATIO, "Minimum 1000 points required");
        require(points % POINTS_TO_SHM_RATIO == 0, "Points must be multiple of 1000");

        uint256 shmAmount = (points * 1 ether) / POINTS_TO_SHM_RATIO;
        require(address(this).balance >= shmAmount, "Insufficient contract balance");

        userPoints[msg.sender].totalPoints -= points;
        userPoints[msg.sender].redeemedPoints += points;
        totalPointsRedeemed += points;

        (bool success, ) = msg.sender.call{value: shmAmount}("");
        require(success, "Transfer failed");

        emit PointsRedeemed(msg.sender, points, shmAmount);
    }

    /**
     * @notice Transfer points to another user
     * @param to Recipient address
     * @param points Amount of points
     */
    function transferPoints(address to, uint256 points) external {
        require(studentRegistry.isVerifiedStudent(to), "Recipient not verified");
        require(userPoints[msg.sender].totalPoints >= points, "Insufficient points");
        require(points > 0, "Invalid amount");

        userPoints[msg.sender].totalPoints -= points;
        userPoints[to].totalPoints += points;

        emit PointsTransferred(msg.sender, to, points);
    }

    /**
     * @notice Get user's point balance
     * @param user Address of the user
     * @return Total points
     */
    function getPointBalance(address user) external view returns (uint256) {
        return userPoints[user].totalPoints;
    }

    /**
     * @notice Get user's points data
     * @param user Address of the user
     * @return User points data struct
     */
    function getUserPointsData(address user) 
        external 
        view 
        returns (UserPointsData memory) 
    {
        return userPoints[user];
    }

    /**
     * @notice Get user's transaction history
     * @param user Address of the user
     * @return Array of transactions
     */
    function getUserTransactions(address user) 
        external 
        view 
        returns (PointTransaction[] memory) 
    {
        return userTransactions[user];
    }

    /**
     * @notice Convert points to INR value
     * @param points Amount of points
     * @return INR value (in wei, 18 decimals)
     */
    function pointsToINR(uint256 points) external pure returns (uint256) {
        return (points * 1 ether) / POINTS_TO_INR_RATIO;
    }

    /**
     * @notice Convert points to SHM value
     * @param points Amount of points
     * @return SHM value (in wei)
     */
    function pointsToSHM(uint256 points) external pure returns (uint256) {
        return (points * 1 ether) / POINTS_TO_SHM_RATIO;
    }

    /**
     * @notice Update base points for activity
     * @param activity Activity type
     * @param newBasePoints New base points value
     */
    function updateBasePoints(ActivityType activity, uint256 newBasePoints) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        basePoints[activity] = newBasePoints;
        emit BasePointsUpdated(activity, newBasePoints);
    }

    /**
     * @notice Update max quality bonus for activity
     * @param activity Activity type
     * @param newMaxBonus New max bonus value
     */
    function updateMaxQualityBonus(ActivityType activity, uint256 newMaxBonus) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        maxQualityBonus[activity] = newMaxBonus;
    }

    /**
     * @notice Get global statistics
     * @return issued Total points issued
     * @return redeemed Total points redeemed
     * @return transactions Total transactions
     */
    function getGlobalStats() 
        external 
        view 
        returns (uint256 issued, uint256 redeemed, uint256 transactions) 
    {
        return (totalPointsIssued, totalPointsRedeemed, totalTransactions);
    }

    /**
     * @notice Fund contract with SHM for redemptions
     */
    function fundContract() external payable onlyRole(ADMIN_ROLE) {
        require(msg.value > 0, "Must send SHM");
    }

    /**
     * @notice Get contract balance
     * @return Balance in wei
     */
    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @notice Grant reward manager role
     * @param manager Address to grant role to
     */
    function grantRewardManagerRole(address manager) external onlyRole(ADMIN_ROLE) {
        grantRole(REWARD_MANAGER_ROLE, manager);
    }

    receive() external payable {}
}

contracts/core/StudentRegistryContract.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../privacy/PrivacyContract.sol";

/**
 * @title StudentRegistryContract
 * @notice Manages student registration and verification with privacy protection
 * @dev Integrates with PrivacyContract for anonymization features
 */
contract StudentRegistryContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");

    uint256 public constant VERIFICATION_FEE = 60 ether; // 60 SHM in wei
    
    PrivacyContract public privacyContract;

    enum StudentStatus {
        NotRegistered,
        Pending,
        Verified,
        Rejected,
        Suspended
    }

    enum UserRole {
        Student,
        Faculty,
        Admin
    }

    struct StudentProfile {
        address studentAddress;
        bytes32 hashedIdentity; // Hash of student ID/documents
        StudentStatus status;
        UserRole role;
        uint256 registrationTime;
        uint256 verificationTime;
        string rejectionReason;
        bool isActive;
    }

    // Mappings
    mapping(address => StudentProfile) public students;
    mapping(bytes32 => address) public identityToAddress;
    mapping(address => uint256) public studentPoints;
    
    uint256 public totalStudents;
    uint256 public verifiedStudents;
    uint256 public pendingVerifications;

    // Events
    event StudentRegistered(
        address indexed student,
        bytes32 hashedIdentity,
        uint256 fee,
        uint256 timestamp
    );
    event StudentVerified(address indexed student, uint256 timestamp);
    event StudentRejected(address indexed student, string reason, uint256 timestamp);
    event StudentSuspended(address indexed student, string reason, uint256 timestamp);
    event StudentReactivated(address indexed student, uint256 timestamp);
    event VerificationFeeCollected(address indexed student, uint256 amount);
    event FeeWithdrawn(address indexed admin, uint256 amount);
    event RoleAssigned(address indexed user, UserRole role);

    constructor(address _privacyContract) {
        require(_privacyContract != address(0), "Invalid privacy contract");
        
        privacyContract = PrivacyContract(_privacyContract);
        
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(VERIFIER_ROLE, msg.sender);
    }

    /**
     * @notice Register as a student with verification fee
     * @param hashedIdentity Hashed student identity (privacy-preserving)
     */
    function registerStudent(bytes32 hashedIdentity) 
        external 
        payable 
        nonReentrant 
    {
        require(msg.value == VERIFICATION_FEE, "Incorrect verification fee");
        require(students[msg.sender].status == StudentStatus.NotRegistered, 
                "Already registered");
        require(identityToAddress[hashedIdentity] == address(0), 
                "Identity already registered");
        require(hashedIdentity != bytes32(0), "Invalid identity hash");

        students[msg.sender] = StudentProfile({
            studentAddress: msg.sender,
            hashedIdentity: hashedIdentity,
            status: StudentStatus.Pending,
            role: UserRole.Student,
            registrationTime: block.timestamp,
            verificationTime: 0,
            rejectionReason: "",
            isActive: true
        });

        identityToAddress[hashedIdentity] = msg.sender;
        totalStudents++;
        pendingVerifications++;

        emit StudentRegistered(msg.sender, hashedIdentity, msg.value, block.timestamp);
        emit VerificationFeeCollected(msg.sender, msg.value);
    }

    /**
     * @notice Verify a student (admin/verifier only)
     * @param studentAddress Address of the student to verify
     */
    function verifyStudent(address studentAddress) 
        external 
        onlyRole(VERIFIER_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Pending, 
                "Student not pending verification");

        students[studentAddress].status = StudentStatus.Verified;
        students[studentAddress].verificationTime = block.timestamp;
        
        verifiedStudents++;
        pendingVerifications--;

        emit StudentVerified(studentAddress, block.timestamp);
    }

    /**
     * @notice Reject a student registration
     * @param studentAddress Address of the student
     * @param reason Reason for rejection
     */
    function rejectStudent(address studentAddress, string memory reason) 
        external 
        onlyRole(VERIFIER_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Pending, 
                "Student not pending verification");
        require(bytes(reason).length > 0, "Reason required");

        students[studentAddress].status = StudentStatus.Rejected;
        students[studentAddress].rejectionReason = reason;
        
        pendingVerifications--;

        emit StudentRejected(studentAddress, reason, block.timestamp);
    }

    /**
     * @notice Suspend a student
     * @param studentAddress Address of the student
     * @param reason Reason for suspension
     */
    function suspendStudent(address studentAddress, string memory reason) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Verified, 
                "Student not verified");
        require(bytes(reason).length > 0, "Reason required");

        students[studentAddress].status = StudentStatus.Suspended;
        students[studentAddress].isActive = false;
        
        verifiedStudents--;

        emit StudentSuspended(studentAddress, reason, block.timestamp);
    }

    /**
     * @notice Reactivate a suspended student
     * @param studentAddress Address of the student
     */
    function reactivateStudent(address studentAddress) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Suspended, 
                "Student not suspended");

        students[studentAddress].status = StudentStatus.Verified;
        students[studentAddress].isActive = true;
        
        verifiedStudents++;

        emit StudentReactivated(studentAddress, block.timestamp);
    }

    /**
     * @notice Check if address is a verified student
     * @param studentAddress Address to check
     * @return True if verified student
     */
    function isVerifiedStudent(address studentAddress) external view returns (bool) {
        return students[studentAddress].status == StudentStatus.Verified &&
               students[studentAddress].isActive;
    }

    /**
     * @notice Get student status
     * @param studentAddress Address of the student
     * @return Current status
     */
    function getStudentStatus(address studentAddress) 
        external 
        view 
        returns (StudentStatus) 
    {
        return students[studentAddress].status;
    }

    /**
     * @notice Get student profile
     * @param studentAddress Address of the student
     * @return Student profile struct
     */
    function getStudentProfile(address studentAddress) 
        external 
        view 
        returns (StudentProfile memory) 
    {
        return students[studentAddress];
    }

    /**
     * @notice Assign role to user (faculty, admin)
     * @param userAddress Address of the user
     * @param role Role to assign
     */
    function assignRole(address userAddress, UserRole role) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(userAddress != address(0), "Invalid address");
        
        if (students[userAddress].studentAddress == address(0)) {
            // Create new profile for non-student users
            students[userAddress] = StudentProfile({
                studentAddress: userAddress,
                hashedIdentity: bytes32(0),
                status: StudentStatus.Verified,
                role: role,
                registrationTime: block.timestamp,
                verificationTime: block.timestamp,
                rejectionReason: "",
                isActive: true
            });
        } else {
            students[userAddress].role = role;
        }

        emit RoleAssigned(userAddress, role);
    }

    /**
     * @notice Get user role
     * @param userAddress Address of the user
     * @return User role
     */
    function getUserRole(address userAddress) external view returns (UserRole) {
        return students[userAddress].role;
    }

    /**
     * @notice Check if user is faculty
     * @param userAddress Address to check
     * @return True if faculty
     */
    function isFaculty(address userAddress) external view returns (bool) {
        return students[userAddress].role == UserRole.Faculty &&
               students[userAddress].isActive;
    }

    /**
     * @notice Check if user is admin
     * @param userAddress Address to check
     * @return True if admin
     */
    function isAdmin(address userAddress) external view returns (bool) {
        return students[userAddress].role == UserRole.Admin &&
               students[userAddress].isActive;
    }

    /**
     * @notice Withdraw collected fees (admin only)
     * @param amount Amount to withdraw
     */
    function withdrawFees(uint256 amount) 
        external 
        onlyRole(ADMIN_ROLE) 
        nonReentrant 
    {
        require(amount <= address(this).balance, "Insufficient balance");
        
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");

        emit FeeWithdrawn(msg.sender, amount);
    }

    /**
     * @notice Get contract balance
     * @return Balance in wei
     */
    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @notice Get registration statistics
     * @return total Total registered students
     * @return verified Total verified students
     * @return pending Total pending verifications
     */
    function getStatistics() 
        external 
        view 
        returns (uint256 total, uint256 verified, uint256 pending) 
    {
        return (totalStudents, verifiedStudents, pendingVerifications);
    }

    /**
     * @notice Grant verifier role
     * @param verifier Address to grant role to
     */
    function grantVerifierRole(address verifier) external onlyRole(ADMIN_ROLE) {
        grantRole(VERIFIER_ROLE, verifier);
    }

    /**
     * @notice Revoke verifier role
     * @param verifier Address to revoke role from
     */
    function revokeVerifierRole(address verifier) external onlyRole(ADMIN_ROLE) {
        revokeRole(VERIFIER_ROLE, verifier);
    }
}

contracts/features/GamificationContract..content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../core/StudentRegistryContract.sol";
import "../core/PointEconomyContract.sol";

/**
 * @title GamificationContract
 * @notice Manages achievements, badges, leaderboards, and milestones
 * @dev Integrates with PointEconomy for rewards
 */
contract GamificationContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant GAME_MANAGER_ROLE = keccak256("GAME_MANAGER_ROLE");

    StudentRegistryContract public studentRegistry;
    PointEconomyContract public pointEconomy;

    enum BadgeType {
        FirstFeedback,
        FeedbackMaster,
        QualityContributor,
        ConsistentUser,
        CommunityHelper,
        TrendSetter,
        ImpactMaker,
        PrivacyChampion
    }

    enum AchievementTier {
        Bronze,
        Silver,
        Gold,
        Platinum,
        Diamond
    }

    struct Badge {
        BadgeType badgeType;
        string name;
        string description;
        uint256 pointReward;
        uint256 requirement;
        bool isActive;
    }

    struct UserAchievement {
        address user;
        BadgeType badgeType;
        AchievementTier tier;
        uint256 earnedAt;
        uint256 pointsAwarded;
    }

    struct Milestone {
        uint256 id;
        string name;
        string description;
        uint256 targetValue;
        uint256 pointReward;
        bool isActive;
    }

    struct LeaderboardEntry {
        address user;
        uint256 totalPoints;
        uint256 totalFeedbacks;
        uint256 badgeCount;
        uint256 rank;
    }

    // Mappings
    mapping(BadgeType => Badge) public badges;
    mapping(address => mapping(BadgeType => bool)) public userBadges;
    mapping(address => UserAchievement[]) public userAchievements;
    mapping(address => uint256) public userBadgeCount;
    mapping(uint256 => Milestone) public milestones;
    mapping(address => mapping(uint256 => bool)) public userMilestones;
    
    // Statistics
    mapping(address => uint256) public feedbackCount;
    mapping(address => uint256) public qualityFeedbackCount;
    mapping(address => uint256) public consecutiveDaysActive;
    
    uint256 public totalBadgesEarned;
    uint256 public milestoneCounter;
    address[] public activeUsers;

    // Events
    event BadgeEarned(
        address indexed user,
        BadgeType badgeType,
        AchievementTier tier,
        uint256 pointsAwarded,
        uint256 timestamp
    );
    event MilestoneAchieved(
        address indexed user,
        uint256 indexed milestoneId,
        uint256 pointsAwarded,
        uint256 timestamp
    );
    event LeaderboardUpdated(address indexed user, uint256 newRank);
    event BadgeCreated(BadgeType badgeType, string name, uint256 pointReward);

    constructor(address _studentRegistry, address payable _pointEconomy) {
        require(_studentRegistry != address(0), "Invalid student registry");
        require(_pointEconomy != address(0), "Invalid point economy");

        studentRegistry = StudentRegistryContract(_studentRegistry);
        pointEconomy = PointEconomyContract(_pointEconomy);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(GAME_MANAGER_ROLE, msg.sender);

        _initializeBadges();
        _initializeMilestones();
    }

    /**
     * @notice Initialize default badges
     */
    function _initializeBadges() internal {
        badges[BadgeType.FirstFeedback] = Badge({
            badgeType: BadgeType.FirstFeedback,
            name: "First Steps",
            description: "Submit your first feedback",
            pointReward: 50,
            requirement: 1,
            isActive: true
        });

        badges[BadgeType.FeedbackMaster] = Badge({
            badgeType: BadgeType.FeedbackMaster,
            name: "Feedback Master",
            description: "Submit 50 feedbacks",
            pointReward: 500,
            requirement: 50,
            isActive: true
        });

        badges[BadgeType.QualityContributor] = Badge({
            badgeType: BadgeType.QualityContributor,
            name: "Quality Contributor",
            description: "Submit 10 high-quality feedbacks",
            pointReward: 300,
            requirement: 10,
            isActive: true
        });

        badges[BadgeType.ConsistentUser] = Badge({
            badgeType: BadgeType.ConsistentUser,
            name: "Consistency Champion",
            description: "Active for 30 consecutive days",
            pointReward: 400,
            requirement: 30,
            isActive: true
        });

        badges[BadgeType.CommunityHelper] = Badge({
            badgeType: BadgeType.CommunityHelper,
            name: "Community Helper",
            description: "Help verify 20 peer feedbacks",
            pointReward: 250,
            requirement: 20,
            isActive: true
        });
    }

    /**
     * @notice Initialize default milestones
     */
    function _initializeMilestones() internal {
        _createMilestone("Novice", "Earn 1000 points", 1000, 100);
        _createMilestone("Contributor", "Earn 5000 points", 5000, 500);
        _createMilestone("Expert", "Earn 10000 points", 10000, 1000);
        _createMilestone("Master", "Earn 25000 points", 25000, 2500);
        _createMilestone("Legend", "Earn 50000 points", 50000, 5000);
    }

    /**
     * @notice Create a new milestone
     */
    function _createMilestone(
        string memory name,
        string memory description,
        uint256 targetValue,
        uint256 pointReward
    ) internal {
        milestoneCounter++;
        milestones[milestoneCounter] = Milestone({
            id: milestoneCounter,
            name: name,
            description: description,
            targetValue: targetValue,
            pointReward: pointReward,
            isActive: true
        });
    }

    /**
     * @notice Record feedback submission and check for achievements
     * @param user Address of the user
     * @param isQuality Whether feedback is high quality
     */
    function recordFeedback(address user, bool isQuality) 
        external 
        onlyRole(GAME_MANAGER_ROLE) 
    {
        require(studentRegistry.isVerifiedStudent(user), "Not verified student");

        feedbackCount[user]++;
        if (isQuality) {
            qualityFeedbackCount[user]++;
        }

        // Check for badge achievements
        _checkBadgeEligibility(user);
        _checkMilestones(user);
    }

    /**
     * @notice Check if user is eligible for any badges
     */
    function _checkBadgeEligibility(address user) internal {
        // First Feedback badge
        if (feedbackCount[user] == 1 && !userBadges[user][BadgeType.FirstFeedback]) {
            _awardBadge(user, BadgeType.FirstFeedback, AchievementTier.Bronze);
        }

        // Feedback Master badge
        if (feedbackCount[user] >= 50 && !userBadges[user][BadgeType.FeedbackMaster]) {
            _awardBadge(user, BadgeType.FeedbackMaster, AchievementTier.Gold);
        }

        // Quality Contributor badge
        if (qualityFeedbackCount[user] >= 10 && !userBadges[user][BadgeType.QualityContributor]) {
            _awardBadge(user, BadgeType.QualityContributor, AchievementTier.Silver);
        }
    }

    /**
     * @notice Award badge to user
     */
    function _awardBadge(address user, BadgeType badgeType, AchievementTier tier) internal {
        Badge memory badge = badges[badgeType];
        require(badge.isActive, "Badge not active");
        require(!userBadges[user][badgeType], "Badge already earned");

        userBadges[user][badgeType] = true;
        userBadgeCount[user]++;
        totalBadgesEarned++;

        // Record achievement
        userAchievements[user].push(UserAchievement({
            user: user,
            badgeType: badgeType,
            tier: tier,
            earnedAt: block.timestamp,
            pointsAwarded: badge.pointReward
        }));

        emit BadgeEarned(user, badgeType, tier, badge.pointReward, block.timestamp);
    }

    /**
     * @notice Check milestone achievements
     */
    function _checkMilestones(address user) internal {
        uint256 userPoints = pointEconomy.getPointBalance(user);

        for (uint256 i = 1; i <= milestoneCounter; i++) {
            Milestone memory milestone = milestones[i];
            
            if (milestone.isActive && 
                !userMilestones[user][i] && 
                userPoints >= milestone.targetValue) {
                
                userMilestones[user][i] = true;
                
                emit MilestoneAchieved(user, i, milestone.pointReward, block.timestamp);
            }
        }
    }

    /**
     * @notice Update consecutive days active
     * @param user Address of the user
     * @param consecutiveDays Number of consecutive days
     */
    function updateConsecutiveDays(address user, uint256 consecutiveDays) 
        external 
        onlyRole(GAME_MANAGER_ROLE) 
    {
        consecutiveDaysActive[user] = consecutiveDays;

        // Check for consistency badge
        if (consecutiveDays >= 30 && !userBadges[user][BadgeType.ConsistentUser]) {
            _awardBadge(user, BadgeType.ConsistentUser, AchievementTier.Gold);
        }
    }

    /**
     * @notice Get user's badges
     * @param user Address of the user
     * @return Array of achievements
     */
    function getUserAchievements(address user) 
        external 
        view 
        returns (UserAchievement[] memory) 
    {
        return userAchievements[user];
    }

    /**
     * @notice Get leaderboard (top N users)
     * @param limit Number of users to return
     * @return Array of leaderboard entries
     */
    function getLeaderboard(uint256 limit) 
        external 
        view 
        returns (LeaderboardEntry[] memory) 
    {
        // In production, this would be optimized with off-chain indexing
        // For now, return a simplified version
        
        uint256 count = limit > activeUsers.length ? activeUsers.length : limit;
        LeaderboardEntry[] memory entries = new LeaderboardEntry[](count);
        
        for (uint256 i = 0; i < count; i++) {
            address user = activeUsers[i];
            entries[i] = LeaderboardEntry({
                user: user,
                totalPoints: pointEconomy.getPointBalance(user),
                totalFeedbacks: feedbackCount[user],
                badgeCount: userBadgeCount[user],
                rank: i + 1
            });
        }
        
        return entries;
    }

    /**
     * @notice Get user statistics
     * @param user Address of the user
     * @return feedbacks Total feedbacks
     * @return qualityFeedbacks Quality feedbacks
     * @return badgeCount Total badges earned
     * @return consecutiveDays Consecutive days active
     */
    function getUserStats(address user) 
        external 
        view 
        returns (
            uint256 feedbacks,
            uint256 qualityFeedbacks,
            uint256 badgeCount,
            uint256 consecutiveDays
        ) 
    {
        return (
            feedbackCount[user],
            qualityFeedbackCount[user],
            userBadgeCount[user],
            consecutiveDaysActive[user]
        );
    }

    /**
     * @notice Check if user has specific badge
     * @param user Address of the user
     * @param badgeType Type of badge
     * @return True if user has badge
     */
    function hasBadge(address user, BadgeType badgeType) 
        external 
        view 
        returns (bool) 
    {
        return userBadges[user][badgeType];
    }

    /**
     * @notice Grant game manager role
     * @param manager Address to grant role to
     */
    function grantGameManagerRole(address manager) external onlyRole(ADMIN_ROLE) {
        grantRole(GAME_MANAGER_ROLE, manager);
    }
}

contracts/features/GovernanceContract.so.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../core/StudentRegistryContract.sol";
import "./ReputationContract.sol";

/**
 * @title GovernanceContract
 * @notice DAO-style governance for campus feedback platform
 * @dev Enables community voting on proposals and platform decisions
 */
contract GovernanceContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant PROPOSER_ROLE = keccak256("PROPOSER_ROLE");

    StudentRegistryContract public studentRegistry;
    ReputationContract public reputationContract;

    enum ProposalType {
        PolicyChange,
        FeatureRequest,
        BudgetAllocation,
        ModeratorElection,
        ThresholdUpdate,
        Other
    }

    enum ProposalStatus {
        Pending,
        Active,
        Passed,
        Rejected,
        Executed,
        Cancelled
    }

    struct Proposal {
        uint256 id;
        ProposalType proposalType;
        string title;
        string description;
        address proposer;
        uint256 createdAt;
        uint256 votingEndsAt;
        uint256 forVotes;
        uint256 againstVotes;
        uint256 abstainVotes;
        ProposalStatus status;
        uint256 executionDelay;
        bool executed;
    }

    struct Vote {
        address voter;
        bool support; // true = for, false = against
        uint256 weight;
        uint256 timestamp;
        string reason;
    }

    // Governance parameters
    uint256 public constant VOTING_PERIOD = 7 days;
    uint256 public constant EXECUTION_DELAY = 2 days;
    uint256 public constant PROPOSAL_THRESHOLD = 100; // Minimum reputation to propose
    uint256 public constant QUORUM_PERCENTAGE = 10; // 10% of eligible voters
    
    // Mappings
    mapping(uint256 => Proposal) public proposals;
    mapping(uint256 => mapping(address => Vote)) public votes;
    mapping(uint256 => mapping(address => bool)) public hasVoted;
    mapping(address => uint256[]) public userProposals;
    
    uint256 public proposalCounter;
    uint256 public totalEligibleVoters;

    // Events
    event ProposalCreated(
        uint256 indexed proposalId,
        ProposalType proposalType,
        string title,
        address indexed proposer,
        uint256 votingEndsAt
    );
    event VoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        bool support,
        uint256 weight,
        string reason
    );
    event ProposalExecuted(uint256 indexed proposalId, uint256 timestamp);
    event ProposalCancelled(uint256 indexed proposalId, string reason);
    event ProposalStatusChanged(uint256 indexed proposalId, ProposalStatus newStatus);

    constructor(address _studentRegistry, address _reputationContract) {
        require(_studentRegistry != address(0), "Invalid student registry");
        require(_reputationContract != address(0), "Invalid reputation contract");

        studentRegistry = StudentRegistryContract(_studentRegistry);
        reputationContract = ReputationContract(_reputationContract);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(PROPOSER_ROLE, msg.sender);
    }

    /**
     * @notice Create a new proposal
     * @param proposalType Type of proposal
     * @param title Proposal title
     * @param description Detailed description
     * @return proposalId ID of created proposal
     */
    function createProposal(
        ProposalType proposalType,
        string memory title,
        string memory description
    ) external returns (uint256) {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        
        // Check reputation threshold
        uint256 reputation = reputationContract.getReputationScore(msg.sender).totalScore;
        require(reputation >= PROPOSAL_THRESHOLD, "Insufficient reputation");
        
        require(bytes(title).length > 0, "Title required");
        require(bytes(description).length > 0, "Description required");

        proposalCounter++;
        uint256 proposalId = proposalCounter;

        proposals[proposalId] = Proposal({
            id: proposalId,
            proposalType: proposalType,
            title: title,
            description: description,
            proposer: msg.sender,
            createdAt: block.timestamp,
            votingEndsAt: block.timestamp + VOTING_PERIOD,
            forVotes: 0,
            againstVotes: 0,
            abstainVotes: 0,
            status: ProposalStatus.Active,
            executionDelay: EXECUTION_DELAY,
            executed: false
        });

        userProposals[msg.sender].push(proposalId);

        emit ProposalCreated(
            proposalId,
            proposalType,
            title,
            msg.sender,
            block.timestamp + VOTING_PERIOD
        );

        return proposalId;
    }

    /**
     * @notice Cast a vote on a proposal
     * @param proposalId ID of the proposal
     * @param support True to vote for, false to vote against
     * @param reason Optional reason for vote
     */
    function castVote(
        uint256 proposalId,
        bool support,
        string memory reason
    ) external {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp < proposal.votingEndsAt, "Voting period ended");
        require(!hasVoted[proposalId][msg.sender], "Already voted");

        // Calculate vote weight based on reputation
        uint256 weight = _calculateVoteWeight(msg.sender);

        votes[proposalId][msg.sender] = Vote({
            voter: msg.sender,
            support: support,
            weight: weight,
            timestamp: block.timestamp,
            reason: reason
        });

        hasVoted[proposalId][msg.sender] = true;

        if (support) {
            proposal.forVotes += weight;
        } else {
            proposal.againstVotes += weight;
        }

        emit VoteCast(proposalId, msg.sender, support, weight, reason);
    }

    /**
     * @notice Calculate vote weight based on reputation
     * @param voter Address of the voter
     * @return Vote weight
     */
    function _calculateVoteWeight(address voter) internal view returns (uint256) {
        uint256 reputation = reputationContract.getReputationScore(voter).totalScore;
        
        // Base weight is 1, bonus based on reputation
        uint256 weight = 1;
        
        if (reputation >= 5000) {
            weight = 5; // Expert
        } else if (reputation >= 2000) {
            weight = 4; // Advanced
        } else if (reputation >= 1000) {
            weight = 3; // Intermediate
        } else if (reputation >= 500) {
            weight = 2; // Contributor
        }
        
        return weight;
    }

    /**
     * @notice Finalize proposal after voting period
     * @param proposalId ID of the proposal
     */
    function finalizeProposal(uint256 proposalId) external {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.votingEndsAt, "Voting still ongoing");

        // Check quorum
        uint256 totalVotes = proposal.forVotes + proposal.againstVotes + proposal.abstainVotes;
        uint256 quorumRequired = (totalEligibleVoters * QUORUM_PERCENTAGE) / 100;
        
        if (totalVotes < quorumRequired) {
            proposal.status = ProposalStatus.Rejected;
            emit ProposalStatusChanged(proposalId, ProposalStatus.Rejected);
            return;
        }

        // Determine outcome
        if (proposal.forVotes > proposal.againstVotes) {
            proposal.status = ProposalStatus.Passed;
            emit ProposalStatusChanged(proposalId, ProposalStatus.Passed);
        } else {
            proposal.status = ProposalStatus.Rejected;
            emit ProposalStatusChanged(proposalId, ProposalStatus.Rejected);
        }
    }

    /**
     * @notice Execute a passed proposal (admin only)
     * @param proposalId ID of the proposal
     */
    function executeProposal(uint256 proposalId) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Passed, "Proposal not passed");
        require(!proposal.executed, "Already executed");
        require(
            block.timestamp >= proposal.votingEndsAt + proposal.executionDelay,
            "Execution delay not met"
        );

        proposal.executed = true;
        proposal.status = ProposalStatus.Executed;

        emit ProposalExecuted(proposalId, block.timestamp);
    }

    /**
     * @notice Cancel a proposal (admin or proposer only)
     * @param proposalId ID of the proposal
     * @param reason Reason for cancellation
     */
    function cancelProposal(uint256 proposalId, string memory reason) external {
        Proposal storage proposal = proposals[proposalId];
        require(
            msg.sender == proposal.proposer || hasRole(ADMIN_ROLE, msg.sender),
            "Not authorized"
        );
        require(proposal.status == ProposalStatus.Active, "Proposal not active");

        proposal.status = ProposalStatus.Cancelled;

        emit ProposalCancelled(proposalId, reason);
    }

    /**
     * @notice Get proposal details
     * @param proposalId ID of the proposal
     * @return Proposal struct
     */
    function getProposal(uint256 proposalId) 
        external 
        view 
        returns (Proposal memory) 
    {
        return proposals[proposalId];
    }

    /**
     * @notice Get vote details
     * @param proposalId ID of the proposal
     * @param voter Address of the voter
     * @return Vote struct
     */
    function getVote(uint256 proposalId, address voter) 
        external 
        view 
        returns (Vote memory) 
    {
        return votes[proposalId][voter];
    }

    /**
     * @notice Get user's proposals
     * @param user Address of the user
     * @return Array of proposal IDs
     */
    function getUserProposals(address user) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return userProposals[user];
    }

    /**
     * @notice Get proposal voting results
     * @param proposalId ID of the proposal
     * @return forVotes Against votes, abstain votes
     */
    function getVotingResults(uint256 proposalId) 
        external 
        view 
        returns (uint256 forVotes, uint256 againstVotes, uint256 abstainVotes) 
    {
        Proposal memory proposal = proposals[proposalId];
        return (proposal.forVotes, proposal.againstVotes, proposal.abstainVotes);
    }

    /**
     * @notice Check if proposal has reached quorum
     * @param proposalId ID of the proposal
     * @return True if quorum reached
     */
    function hasReachedQuorum(uint256 proposalId) external view returns (bool) {
        Proposal memory proposal = proposals[proposalId];
        uint256 totalVotes = proposal.forVotes + proposal.againstVotes + proposal.abstainVotes;
        uint256 quorumRequired = (totalEligibleVoters * QUORUM_PERCENTAGE) / 100;
        
        return totalVotes >= quorumRequired;
    }

    /**
     * @notice Update total eligible voters (admin only)
     * @param count New count
     */
    function updateEligibleVoters(uint256 count) external onlyRole(ADMIN_ROLE) {
        totalEligibleVoters = count;
    }

    /**
     * @notice Grant proposer role
     * @param proposer Address to grant role to
     */
    function grantProposerRole(address proposer) external onlyRole(ADMIN_ROLE) {
        grantRole(PROPOSER_ROLE, proposer);
    }
}

contracts/features/ReputationContract.so.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../core/StudentRegistryContract.sol";

/**
 * @title ReputationContract
 * @notice Manages user reputation and credibility scores
 * @dev Calculates reputation based on multiple factors
 */
contract ReputationContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REPUTATION_MANAGER_ROLE = keccak256("REPUTATION_MANAGER_ROLE");

    StudentRegistryContract public studentRegistry;

    struct ReputationScore {
        uint256 totalScore;
        uint256 feedbackQuality;
        uint256 communityEngagement;
        uint256 consistency;
        uint256 helpfulness;
        uint256 lastUpdated;
    }

    struct ReputationHistory {
        uint256 timestamp;
        int256 change;
        string reason;
    }

    // Mappings
    mapping(address => ReputationScore) public reputationScores;
    mapping(address => ReputationHistory[]) public reputationHistory;
    mapping(address => uint256) public trustLevel; // 0-5
    
    uint256 public constant MAX_REPUTATION = 10000;
    uint256 public constant INITIAL_REPUTATION = 100;

    // Events
    event ReputationUpdated(
        address indexed user,
        uint256 newScore,
        int256 change,
        string reason
    );
    event TrustLevelChanged(address indexed user, uint256 newLevel);

    constructor(address _studentRegistry) {
        require(_studentRegistry != address(0), "Invalid student registry");
        
        studentRegistry = StudentRegistryContract(_studentRegistry);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(REPUTATION_MANAGER_ROLE, msg.sender);
    }

    /**
     * @notice Initialize reputation for new user
     * @param user Address of the user
     */
    function initializeReputation(address user) 
        external 
        onlyRole(REPUTATION_MANAGER_ROLE) 
    {
        require(studentRegistry.isVerifiedStudent(user), "Not verified student");
        require(reputationScores[user].lastUpdated == 0, "Already initialized");

        reputationScores[user] = ReputationScore({
            totalScore: INITIAL_REPUTATION,
            feedbackQuality: 20,
            communityEngagement: 20,
            consistency: 20,
            helpfulness: 20,
            lastUpdated: block.timestamp
        });

        trustLevel[user] = 1; // Novice level

        emit ReputationUpdated(user, INITIAL_REPUTATION, int256(INITIAL_REPUTATION), "Initial reputation");
    }

    /**
     * @notice Update reputation based on feedback quality
     * @param user Address of the user
     * @param qualityScore Quality score (0-100)
     */
    function updateFeedbackQuality(address user, uint256 qualityScore) 
        external 
        onlyRole(REPUTATION_MANAGER_ROLE) 
    {
        require(qualityScore <= 100, "Invalid quality score");

        ReputationScore storage score = reputationScores[user];
        
        // Calculate change based on quality
        int256 change = 0;
        if (qualityScore >= 80) {
            change = 10;
        } else if (qualityScore >= 60) {
            change = 5;
        } else if (qualityScore >= 40) {
            change = 0;
        } else {
            change = -5;
        }

        _updateReputation(user, change, "Feedback quality");
        score.feedbackQuality = (score.feedbackQuality + qualityScore) / 2;
    }

    /**
     * @notice Update reputation based on community engagement
     * @param user Address of the user
     * @param engagementPoints Engagement points earned
     */
    function updateCommunityEngagement(address user, uint256 engagementPoints) 
        external 
        onlyRole(REPUTATION_MANAGER_ROLE) 
    {
        int256 change = int256(engagementPoints / 10);
        _updateReputation(user, change, "Community engagement");
        
        ReputationScore storage score = reputationScores[user];
        score.communityEngagement += engagementPoints;
    }

    /**
     * @notice Update reputation based on consistency
     * @param user Address of the user
     * @param consecutiveDays Number of consecutive days active
     */
    function updateConsistency(address user, uint256 consecutiveDays) 
        external 
        onlyRole(REPUTATION_MANAGER_ROLE) 
    {
        int256 change = 0;
        if (consecutiveDays >= 30) {
            change = 20;
        } else if (consecutiveDays >= 14) {
            change = 10;
        } else if (consecutiveDays >= 7) {
            change = 5;
        }

        if (change > 0) {
            _updateReputation(user, change, "Consistency bonus");
            reputationScores[user].consistency += uint256(change);
        }
    }

    /**
     * @notice Update reputation based on helpfulness
     * @param user Address of the user
     * @param helpfulActions Number of helpful actions
     */
    function updateHelpfulness(address user, uint256 helpfulActions) 
        external 
        onlyRole(REPUTATION_MANAGER_ROLE) 
    {
        int256 change = int256(helpfulActions * 3);
        _updateReputation(user, change, "Helpfulness");
        
        reputationScores[user].helpfulness += helpfulActions;
    }

    /**
     * @notice Internal function to update reputation
     */
    function _updateReputation(address user, int256 change, string memory reason) internal {
        ReputationScore storage score = reputationScores[user];
        
        // Apply change
        if (change > 0) {
            score.totalScore = score.totalScore + uint256(change);
            if (score.totalScore > MAX_REPUTATION) {
                score.totalScore = MAX_REPUTATION;
            }
        } else if (change < 0) {
            uint256 decrease = uint256(-change);
            if (score.totalScore > decrease) {
                score.totalScore -= decrease;
            } else {
                score.totalScore = 0;
            }
        }

        score.lastUpdated = block.timestamp;

        // Record history
        reputationHistory[user].push(ReputationHistory({
            timestamp: block.timestamp,
            change: change,
            reason: reason
        }));

        // Update trust level
        _updateTrustLevel(user);

        emit ReputationUpdated(user, score.totalScore, change, reason);
    }

    /**
     * @notice Update trust level based on reputation
     */
    function _updateTrustLevel(address user) internal {
        uint256 reputation = reputationScores[user].totalScore;
        uint256 oldLevel = trustLevel[user];
        uint256 newLevel;

        if (reputation >= 5000) {
            newLevel = 5; // Expert
        } else if (reputation >= 2000) {
            newLevel = 4; // Advanced
        } else if (reputation >= 1000) {
            newLevel = 3; // Intermediate
        } else if (reputation >= 500) {
            newLevel = 2; // Contributor
        } else {
            newLevel = 1; // Novice
        }

        if (newLevel != oldLevel) {
            trustLevel[user] = newLevel;
            emit TrustLevelChanged(user, newLevel);
        }
    }

    /**
     * @notice Get user reputation score
     * @param user Address of the user
     * @return Reputation score struct
     */
    function getReputationScore(address user) 
        external 
        view 
        returns (ReputationScore memory) 
    {
        return reputationScores[user];
    }

    /**
     * @notice Get user reputation history
     * @param user Address of the user
     * @return Array of reputation history
     */
    function getReputationHistory(address user) 
        external 
        view 
        returns (ReputationHistory[] memory) 
    {
        return reputationHistory[user];
    }

    /**
     * @notice Get user trust level
     * @param user Address of the user
     * @return Trust level (0-5)
     */
    function getTrustLevel(address user) external view returns (uint256) {
        return trustLevel[user];
    }

    /**
     * @notice Check if user is trusted (level >= 3)
     * @param user Address of the user
     * @return True if trusted
     */
    function isTrustedUser(address user) external view returns (bool) {
        return trustLevel[user] >= 3;
    }

    /**
     * @notice Grant reputation manager role
     * @param manager Address to grant role to
     */
    function grantReputationManagerRole(address manager) external onlyRole(ADMIN_ROLE) {
        grantRole(REPUTATION_MANAGER_ROLE, manager);
    }
}

contracts/features/SocialNetworkContract.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../core/StudentRegistryContract.sol";

/**
 * @title SocialNetworkContract
 * @notice Manages social features: following, communities, and social interactions
 * @dev Enables community building and peer connections
 */
contract SocialNetworkContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");

    StudentRegistryContract public studentRegistry;

    struct Community {
        uint256 id;
        string name;
        string description;
        address creator;
        uint256 createdAt;
        uint256 memberCount;
        bool isActive;
    }

    struct UserProfile {
        address userAddress;
        string bio;
        uint256 followerCount;
        uint256 followingCount;
        uint256 communityCount;
        bool isPublic;
    }

    // Mappings
    mapping(address => UserProfile) public userProfiles;
    mapping(address => mapping(address => bool)) public isFollowing;
    mapping(address => address[]) public followers;
    mapping(address => address[]) public following;
    
    mapping(uint256 => Community) public communities;
    mapping(uint256 => address[]) public communityMembers;
    mapping(uint256 => mapping(address => bool)) public isCommunityMember;
    mapping(address => uint256[]) public userCommunities;
    
    uint256 public communityCounter;
    uint256 public totalConnections;

    // Events
    event UserFollowed(address indexed follower, address indexed followed, uint256 timestamp);
    event UserUnfollowed(address indexed follower, address indexed unfollowed, uint256 timestamp);
    event CommunityCreated(uint256 indexed communityId, string name, address indexed creator);
    event CommunityJoined(uint256 indexed communityId, address indexed member);
    event CommunityLeft(uint256 indexed communityId, address indexed member);
    event ProfileUpdated(address indexed user, string bio);

    constructor(address _studentRegistry) {
        require(_studentRegistry != address(0), "Invalid student registry");
        
        studentRegistry = StudentRegistryContract(_studentRegistry);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Update user profile
     * @param bio User biography
     * @param isPublic Whether profile is public
     */
    function updateProfile(string memory bio, bool isPublic) external {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");

        userProfiles[msg.sender].userAddress = msg.sender;
        userProfiles[msg.sender].bio = bio;
        userProfiles[msg.sender].isPublic = isPublic;

        emit ProfileUpdated(msg.sender, bio);
    }

    /**
     * @notice Follow another user
     * @param userToFollow Address to follow
     */
    function followUser(address userToFollow) external {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(studentRegistry.isVerifiedStudent(userToFollow), "Target not verified");
        require(msg.sender != userToFollow, "Cannot follow yourself");
        require(!isFollowing[msg.sender][userToFollow], "Already following");

        isFollowing[msg.sender][userToFollow] = true;
        followers[userToFollow].push(msg.sender);
        following[msg.sender].push(userToFollow);

        userProfiles[msg.sender].followingCount++;
        userProfiles[userToFollow].followerCount++;
        totalConnections++;

        emit UserFollowed(msg.sender, userToFollow, block.timestamp);
    }

    /**
     * @notice Unfollow a user
     * @param userToUnfollow Address to unfollow
     */
    function unfollowUser(address userToUnfollow) external {
        require(isFollowing[msg.sender][userToUnfollow], "Not following");

        isFollowing[msg.sender][userToUnfollow] = false;
        
        // Remove from arrays (simplified - in production use more efficient method)
        _removeFromArray(followers[userToUnfollow], msg.sender);
        _removeFromArray(following[msg.sender], userToUnfollow);

        userProfiles[msg.sender].followingCount--;
        userProfiles[userToUnfollow].followerCount--;
        totalConnections--;

        emit UserUnfollowed(msg.sender, userToUnfollow, block.timestamp);
    }

    /**
     * @notice Create a new community
     * @param name Community name
     * @param description Community description
     * @return communityId ID of created community
     */
    function createCommunity(string memory name, string memory description) 
        external 
        returns (uint256) 
    {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(bytes(name).length > 0, "Name required");

        communityCounter++;
        uint256 communityId = communityCounter;

        communities[communityId] = Community({
            id: communityId,
            name: name,
            description: description,
            creator: msg.sender,
            createdAt: block.timestamp,
            memberCount: 1,
            isActive: true
        });

        // Creator automatically joins
        isCommunityMember[communityId][msg.sender] = true;
        communityMembers[communityId].push(msg.sender);
        userCommunities[msg.sender].push(communityId);
        userProfiles[msg.sender].communityCount++;

        emit CommunityCreated(communityId, name, msg.sender);
        emit CommunityJoined(communityId, msg.sender);

        return communityId;
    }

    /**
     * @notice Join a community
     * @param communityId ID of community to join
     */
    function joinCommunity(uint256 communityId) external {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(communities[communityId].isActive, "Community not active");
        require(!isCommunityMember[communityId][msg.sender], "Already a member");

        isCommunityMember[communityId][msg.sender] = true;
        communityMembers[communityId].push(msg.sender);
        userCommunities[msg.sender].push(communityId);
        
        communities[communityId].memberCount++;
        userProfiles[msg.sender].communityCount++;

        emit CommunityJoined(communityId, msg.sender);
    }

    /**
     * @notice Leave a community
     * @param communityId ID of community to leave
     */
    function leaveCommunity(uint256 communityId) external {
        require(isCommunityMember[communityId][msg.sender], "Not a member");
        require(communities[communityId].creator != msg.sender, "Creator cannot leave");

        isCommunityMember[communityId][msg.sender] = false;
        
        _removeFromArray(communityMembers[communityId], msg.sender);
        _removeFromUintArray(userCommunities[msg.sender], communityId);
        
        communities[communityId].memberCount--;
        userProfiles[msg.sender].communityCount--;

        emit CommunityLeft(communityId, msg.sender);
    }

    /**
     * @notice Get user's followers
     * @param user Address of the user
     * @return Array of follower addresses
     */
    function getFollowers(address user) external view returns (address[] memory) {
        return followers[user];
    }

    /**
     * @notice Get users that user is following
     * @param user Address of the user
     * @return Array of addresses being followed
     */
    function getFollowing(address user) external view returns (address[] memory) {
        return following[user];
    }

    /**
     * @notice Get community members
     * @param communityId ID of the community
     * @return Array of member addresses
     */
    function getCommunityMembers(uint256 communityId) 
        external 
        view 
        returns (address[] memory) 
    {
        return communityMembers[communityId];
    }

    /**
     * @notice Get user's communities
     * @param user Address of the user
     * @return Array of community IDs
     */
    function getUserCommunities(address user) external view returns (uint256[] memory) {
        return userCommunities[user];
    }

    /**
     * @notice Get user profile
     * @param user Address of the user
     * @return User profile struct
     */
    function getUserProfile(address user) external view returns (UserProfile memory) {
        return userProfiles[user];
    }

    /**
     * @notice Helper function to remove address from array
     */
    function _removeFromArray(address[] storage array, address element) internal {
        for (uint256 i = 0; i < array.length; i++) {
            if (array[i] == element) {
                array[i] = array[array.length - 1];
                array.pop();
                break;
            }
        }
    }

    /**
     * @notice Helper function to remove uint from array
     */
    function _removeFromUintArray(uint256[] storage array, uint256 element) internal {
        for (uint256 i = 0; i < array.length; i++) {
            if (array[i] == element) {
                array[i] = array[array.length - 1];
                array.pop();
                break;
            }
        }
    }

    /**
     * @notice Grant moderator role
     * @param moderator Address to grant role to
     */
    function grantModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        grantRole(MODERATOR_ROLE, moderator);
    }
}

contracts/privacy/PrivacyContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title PrivacyContract
 * @notice Manages privacy-preserving features including anonymization and data protection
 * @dev Implements zero-knowledge verification and GDPR compliance mechanisms
 */
contract PrivacyContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");

    // Privacy settings
    struct PrivacySettings {
        bool isAnonymous;
        bool allowDataCollection;
        uint256 dataRetentionPeriod; // in days
        uint256 lastUpdated;
    }

    // Data deletion request
    struct DeletionRequest {
        address requester;
        uint256 requestTime;
        bool processed;
        bool approved;
        string reason;
    }

    // Mappings
    mapping(address => PrivacySettings) public userPrivacySettings;
    mapping(address => DeletionRequest) public deletionRequests;
    mapping(bytes32 => bool) public verifiedProofs; // For zero-knowledge proofs
    mapping(uint256 => bool) public anonymizedContent; // Content ID => is anonymized

    // Events
    event PrivacySettingsUpdated(address indexed user, bool isAnonymous, uint256 timestamp);
    event DeletionRequested(address indexed user, uint256 timestamp);
    event DeletionProcessed(address indexed user, bool approved, uint256 timestamp);
    event ProofVerified(bytes32 indexed proofHash, bool valid, uint256 timestamp);
    event ContentAnonymized(uint256 indexed contentId, uint256 timestamp);
    event DataAccessLogged(address indexed accessor, address indexed subject, uint256 timestamp);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Update user privacy settings
     * @param isAnonymous Whether user wants anonymous interactions
     * @param allowDataCollection Whether to allow data collection for analytics
     * @param retentionDays Data retention period in days
     */
    function updatePrivacySettings(
        bool isAnonymous,
        bool allowDataCollection,
        uint256 retentionDays
    ) external {
        require(retentionDays >= 30 && retentionDays <= 3650, "Invalid retention period");

        userPrivacySettings[msg.sender] = PrivacySettings({
            isAnonymous: isAnonymous,
            allowDataCollection: allowDataCollection,
            dataRetentionPeriod: retentionDays,
            lastUpdated: block.timestamp
        });

        emit PrivacySettingsUpdated(msg.sender, isAnonymous, block.timestamp);
    }

    /**
     * @notice Get user privacy settings
     * @param user Address of the user
     * @return Privacy settings struct
     */
    function getPrivacySettings(address user) external view returns (PrivacySettings memory) {
        return userPrivacySettings[user];
    }

    /**
     * @notice Check if user prefers anonymous interactions
     * @param user Address of the user
     * @return True if user wants anonymity
     */
    function isAnonymousUser(address user) external view returns (bool) {
        return userPrivacySettings[user].isAnonymous;
    }

    /**
     * @notice Request data deletion (GDPR right to be forgotten)
     * @param reason Reason for deletion request
     */
    function requestDataDeletion(string memory reason) external {
        require(deletionRequests[msg.sender].requestTime == 0 || 
                deletionRequests[msg.sender].processed, 
                "Pending deletion request exists");

        deletionRequests[msg.sender] = DeletionRequest({
            requester: msg.sender,
            requestTime: block.timestamp,
            processed: false,
            approved: false,
            reason: reason
        });

        emit DeletionRequested(msg.sender, block.timestamp);
    }

    /**
     * @notice Process data deletion request (admin only)
     * @param user Address of the user
     * @param approved Whether to approve the deletion
     */
    function processDeletionRequest(address user, bool approved) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(deletionRequests[user].requestTime > 0, "No deletion request found");
        require(!deletionRequests[user].processed, "Request already processed");

        deletionRequests[user].processed = true;
        deletionRequests[user].approved = approved;

        emit DeletionProcessed(user, approved, block.timestamp);
    }

    /**
     * @notice Verify zero-knowledge proof
     * @param proof The proof bytes
     * @param publicInput Public input for verification
     * @return True if proof is valid
     */
    function verifyZKProof(bytes memory proof, bytes32 publicInput) 
        external 
        returns (bool) 
    {
        // Simplified ZK proof verification
        // In production, integrate with actual ZK proof library (e.g., Groth16, PLONK)
        bytes32 proofHash = keccak256(abi.encodePacked(proof, publicInput));
        
        // For demo: proof is valid if it hasn't been used before
        bool isValid = !verifiedProofs[proofHash];
        
        if (isValid) {
            verifiedProofs[proofHash] = true;
            emit ProofVerified(proofHash, true, block.timestamp);
        }

        return isValid;
    }

    /**
     * @notice Mark content as anonymized
     * @param contentId ID of the content
     */
    function anonymizeContent(uint256 contentId) 
        external 
        onlyRole(MODERATOR_ROLE) 
    {
        require(!anonymizedContent[contentId], "Content already anonymized");
        
        anonymizedContent[contentId] = true;
        emit ContentAnonymized(contentId, block.timestamp);
    }

    /**
     * @notice Check if content is anonymized
     * @param contentId ID of the content
     * @return True if content is anonymized
     */
    function isContentAnonymized(uint256 contentId) external view returns (bool) {
        return anonymizedContent[contentId];
    }

    /**
     * @notice Log data access for audit trail
     * @param subject Address whose data is being accessed
     */
    function logDataAccess(address subject) external {
        emit DataAccessLogged(msg.sender, subject, block.timestamp);
    }

    /**
     * @notice Check if data retention period has expired
     * @param user Address of the user
     * @return True if data should be deleted
     */
    function shouldDeleteData(address user) external view returns (bool) {
        PrivacySettings memory settings = userPrivacySettings[user];
        if (settings.lastUpdated == 0) return false;
        
        uint256 retentionSeconds = settings.dataRetentionPeriod * 1 days;
        return block.timestamp > settings.lastUpdated + retentionSeconds;
    }

    /**
     * @notice Grant moderator role
     * @param moderator Address to grant role to
     */
    function grantModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        grantRole(MODERATOR_ROLE, moderator);
    }

    /**
     * @notice Revoke moderator role
     * @param moderator Address to revoke role from
     */
    function revokeModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        revokeRole(MODERATOR_ROLE, moderator);
    }
}

